import os
import secrets
from urllib.parse import urlencode
from flask import Flask, redirect, url_for, session, request, flash

app = Flask(__name__)
app.secret_key = os.urandom(24) # Used for session management

# OIDC Provider Configuration (Replace with your actual provider's details)
OIDC_PROVIDER_URL = "YOUR_OIDC_PROVIDER_BASE_URL" # e.g., "https://accounts.google.com" or "https://your-keycloak-instance/auth/realms/your-realm"
OIDC_CLIENT_ID = "YOUR_CLIENT_ID"
OIDC_REDIRECT_URI = "http://localhost:5000/callback" # Must match what's registered with the OIDC provider

# Helper function to discover OIDC endpoints
def get_oidc_config():
    # In a real app, you'd cache this or fetch from OIDC_PROVIDER_URL/.well-known/openid-configuration
    # For simplicity, we'll hardcode or assume common endpoints for this example.
    # Replace with actual discovery if needed, or get these from your provider's docs.
    return {
        "authorization_endpoint": f"{OIDC_PROVIDER_URL}/protocol/openid-connect/auth",
        "token_endpoint": f"{OIDC_PROVIDER_URL}/protocol/openid-connect/token",
        "userinfo_endpoint": f"{OIDC_PROVIDER_URL}/protocol/openid-connect/userinfo",
        "jwks_uri": f"{OIDC_PROVIDER_URL}/protocol/openid-connect/certs",
    }

@app.route('/')
def index():
    if 'user_info' in session:
        user_info = session['user_info']
        return f"""
            <h1>Welcome, {user_info.get('name', user_info.get('email', 'User'))}!</h1>
            <p>You are authenticated.</p>
            <p><a href="/logout">Logout</a></p>
            <pre>{user_info}</pre>
        """
    return """
        <h1>Welcome to the Admin Dashboard SSO Client</h1>
        <p>Please authenticate using OpenID Connect.</p>
        <p><a href="/login">Login with OIDC</a></p>
    """

@app.route('/login')
def login():
    oidc_config = get_oidc_config()
    auth_endpoint = oidc_config["authorization_endpoint"]

    params = {
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": "openid profile email", # request basic profile and email info
        "response_type": "id_token",
    }

    # Store a state parameter to prevent CSRF attacks
    state = secrets.token_urlsafe(32)
    session['oidc_state'] = state
    params['state'] = state

    auth_url = f"{auth_endpoint}?{urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    # Verify state parameter to prevent CSRF
    if 'state' not in request.args or request.args['state'] != session.pop('oidc_state', None):
        flash("Invalid state parameter. Possible CSRF attack.", "danger")
        return redirect(url_for('index'))

    # id_token is returned in the URL fragment, which Flask's request.args doesn't parse directly.
    # In a real application, you'd typically handle this on the frontend using JavaScript
    # or ensure your OIDC provider is configured to send `id_token` in the query string
    # (which is technically not standard for `response_type=id_token` but some providers allow).

    # For this example, assuming the OIDC provider sends id_token in the query string (non-standard but simplified for server-side demo).
    # If your provider strictly adheres to fragment, you'd need a JS frontend.
    id_token_jwt = request.args.get('id_token')

    if not id_token_jwt:
        error = request.args.get('error', 'unknown error')
        error_description = request.args.get('error_description', 'No id_token received.')
        flash(f"Authentication failed: {error} - {error_description}", "danger")
        return redirect(url_for('index'))

    # In a real application, you *must* validate the ID Token:
    # 1. Parse the JWT (decode header and payload)
    # 2. Verify signature using OIDC provider's public keys (JWKS)
    # 3. Validate claims: issuer, audience, expiry, iat, nonce (if used), etc.
    # This example skips full validation for brevity but it's CRITICAL for security.
    # Use a library like `python-jose` or `Authlib` for proper JWT validation.

    # For demonstration, we'll just decode the base64 part of the payload (simplified & insecure!)
    import base64
    import json

    try:
        # JWTs are base64-encoded parts separated by dots: header.payload.signature
        _header, payload_encoded, _signature = id_token_jwt.split('.')
        payload_decoded = base64.urlsafe_b64decode(payload_encoded + '==').decode('utf-8')
        user_info = json.loads(payload_decoded)

        # Store user info in session
        session['user_info'] = user_info
        flash("Successfully authenticated!", "success")
        return redirect(url_for('index'))
    except Exception as e:
        flash(f"Error processing ID Token: {e}", "danger")
        return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('user_info', None)
    session.pop('oidc_state', None)
    flash("You have been logged out.", "info")
    return redirect(url_for('index'))

